import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { tap } from 'rxjs/operators';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';

const TOKEN_KEY = 'auth_token';
const USER_KEY = 'user';

export interface AdminUser {
  username: string;
  role: string;
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;

  private _token = signal<string | null>(localStorage.getItem(TOKEN_KEY));
  private _user = signal<AdminUser | null>(this.readUser());

  readonly isLoggedIn = computed(() => !!this._token());
  readonly token = this._token.asReadonly();
  readonly user = this._user.asReadonly();
  readonly isAdmin = computed(() => this._user()?.role === 'admin');

  constructor(
    private http: HttpClient,
    private router: Router,
  ) {}

  /** Admin credential login. POST /admin/login -> { token }. */
  adminLogin(username: string, password: string): Observable<{ token: string; role: string }> {
    return this.http
      .post<{ token: string; role: string }>(`${this.apiUrl}/admin/login`, { username, password })
      .pipe(
        tap((response) => {
          this.persistSession(response.token, { username, role: response.role ?? 'admin' });
        }),
      );
  }

  /**
   * Demo Mode bypass — lets reviewers and the screenshot system reach the
   * authenticated admin UI without a live backend. Seeds mock admin credentials
   * and navigates to the admin dashboard.
   */
  demoLogin(): void {
    const demoUser: AdminUser = { username: 'demo-admin', role: 'admin' };
    const demoToken = 'demo-token';
    this.persistSession(demoToken, demoUser);
    localStorage.setItem('access_token', demoToken);
    localStorage.setItem('isAuthenticated', 'true');
    this.router.navigate(['/admin']);
  }

  logout(): void {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
    localStorage.removeItem('access_token');
    localStorage.removeItem('isAuthenticated');
    this._token.set(null);
    this._user.set(null);
    this.router.navigate(['/admin/login']);
  }

  private persistSession(token: string, user: AdminUser): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    this._token.set(token);
    this._user.set(user);
  }

  private readUser(): AdminUser | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as AdminUser) : null;
    } catch {
      return null;
    }
  }
}
